// async 的精神：等 I/O 的空檔做別的（這裡用同步示意）
fn fetch(name: &str) -> String {
    format!("{} 的資料", name)
}

fn main() {
    let a = fetch("使用者");
    let b = fetch("訂單");
    println!("{} / {}", a, b);
    println!("async 讓這些 I/O 能並行等待、不互相卡");
}

