// Axum handler 的精神：收請求、回回應（這裡用普通函式示意）
fn hello() -> &'static str {
    "哈囉 from Axum"
}

fn user(id: u32) -> String {
    format!("使用者 {}", id)
}

fn main() {
    println!("GET /        -> {}", hello());
    println!("GET /users/7 -> {}", user(7));
}

// sqlx 的精神：參數化查詢（用 $1 綁定，不字串拼接）
fn safe_query(user_id: i32) -> String {
    format!("SELECT * FROM users WHERE id = $1  -- bind({})", user_id)
}

fn main() {
    println!("{}", safe_query(42));
    println!("=> 用 bind 綁參數，使用者輸入永遠進不了 SQL 結構，防 injection");
}

// Serde 的精神：struct 跟 JSON 互轉（這裡手動示意）
struct User { name: String, age: u32 }

fn to_json(u: &User) -> String {
