    ( $( $x:expr ),* ) => {{
        let mut v = Vec::new();
        $( v.push($x); )*
        v
    }};
}

fn main() {
    let v = my_vec![10, 20, 30];
    println!("{:?}", v);
}

fn main() {
    let mut num = 5;
    let r = &mut num as *mut i32;   // 裸指標

    unsafe {
        *r = 10;                    // 只能在 unsafe 裡解引用
        println!("num = {}", *r);
    }
    println!("外面 num = {}", num);
}

fn main() {
    let targets = [
        ("WebAssembly", "瀏覽器裡跑高速運算"),
        ("CLI 工具", "ripgrep / fd，啟動快、單一執行檔"),
        ("嵌入式 / IoT", "no_std，無作業系統也能跑"),
        ("區塊鏈", "Solana / Polkadot"),
    ];
    for (name, use_case) in targets {
        println!("{:14} -> {}", name, use_case);
    }
}

lessons.content:
把整章學的串成一個小 API——這就是真實 Rust 後端的骨架。

### 1. 技術棧

- **Axum**：web 框架 / 路由
- **sqlx**：連 PostgreSQL、編譯期檢查 SQL
- **Serde**：回傳 JSON
- **Tokio**：async runtime
- **anyhow**：錯誤處理

### 2. 完整骨架

```rust
use axum::{routing::get, Json, Router, extract::State};
use serde::Serialize;
use sqlx::postgres::PgPool;

#[derive(Serialize, sqlx::FromRow)]
struct User { id: i32, name: String }

// handler：查所有 user、回 JSON
async fn list_users(State(pool): State<PgPool>)
    -> Result<Json<Vec<User>>, String>
{
    let users = sqlx::query_as::<_, User>("SELECT id, name FROM users")
        .fetch_all(&pool)
        .await
        .map_err(|e| e.to_string())?;
    Ok(Json(users))
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let pool = PgPool::connect("postgres://localhost/mydb").await?;
    let app = Router::new()
        .route("/users", get(list_users))
        .with_state(pool);                    // 把連線池注入 handler

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await?;
    axum::serve(listener, app).await?;
    Ok(())
}
```

### 3. 這個小 API 用到的整章觀念

- **所有權 / 借用**：&pool 借用連線池
- **Result + ?**：每一步出錯就往上拋
- **Serde**：#[derive(Serialize)] 自動轉 JSON
- **泛型**：query_as::<_, User> 指定回傳型別
- **async / Tokio**：handler 都是 async

### 4. 下一步

加上 POST（建立）、路徑參數（查單一 user）、middleware（驗證），就是一個完整可上線的 API。部署時「cargo build --release」編出單一執行檔、丟進 Docker，超輕量。

### 🎯 重點回顧

- Axum（路由）+ sqlx（DB）+ Serde（JSON）+ Tokio（async）= Rust 後端標準棧
- 整章觀念（所有權、Result+?、泛型、async）全用上
- --release 編單一執行檔 + Docker，部署超輕量

**☕ 用人話講**

整章總整合——用 **Axum + sqlx + Serde + Tokio + anyhow** 做一個真的能跑的 REST API：Axum 定路由、sqlx 連 PostgreSQL（編譯期還幫你檢查 SQL）、Serde 把結果自動轉 JSON、`?` 處理每一步的錯誤。這個小 API 把整章學的全用上了：**所有權/借用**、**Result + ?**、**Serde**、**泛型**、**async/Tokio**。**一句話記住**：像期末作品——把這章所有零件組成一台能跑的車；再加上 POST、路徑參數、驗證 middleware 就是完整可上線的後端，最後 `cargo build --release` 編出單一執行檔丟進 Docker，部署超輕量。這就是 Rust 寫後端的真實樣貌。

playgrounds.initialCode:
// 把整章串起來：查資料 -> 組成物件 -> 回 JSON（示意）
struct User { id: i32, name: String }

fn list_users() -> String {
    let users = vec![
        User { id: 1, name: String::from("Nami") },
        User { id: 2, name: String::from("Luffy") },
    ];
    let items: Vec<String> = users.iter()
        .map(|u| format!("{{\"id\":{},\"name\":\"{}\"}}", u.id, u.name))
        .collect();
    format!("[{}]", items.join(","))
}

fn main() {
    println!("GET /users -> {}", list_users());
}
